mapper.select:
SELECT r.id, r.inviter_id, r.invitee_id, r.referral_code, r.status,
       r.signup_bonus_given, r.sub_bonus_given, r.created_at
FROM sm_referral r
WHERE r.inviter_id = #{inviterId}
  AND r.invitee_id = #{inviteeId}

mapper.update:
UPDATE sm_referral
SET status = #{status}
WHERE id = #{id}

UPDATE sm_referral
SET signup_bonus_given = 1
WHERE id = #{id}

UPDATE sm_referral
SET sub_bonus_given = 1
WHERE id = #{id}

mapper.select:
SELECT event_type, plan_name, inviter_reward, invitee_reward
FROM sm_referral_reward
WHERE event_type = #{eventType}
  AND plan_name = #{planName}

SELECT COUNT(*)
FROM sm_referral
WHERE inviter_id = #{inviterId}
